 1	import * as React from 'react';
 2	import { useApplicationFromPAV } from '@odf/mco/hooks/use-application-pav';
 3	import { ProtectedApplicationViewKind } from '@odf/mco/types/pav';
 4	import { CommonModalProps } from '@odf/shared/modals';
 5	import {
 6	  Modal,
 7	  ModalVariant,
 8	  Bullseye,
 9	  Spinner,
10	  Alert,
11	} from '@patternfly/react-core';
12	import { AppManagePoliciesModal } from '../app-manage-policies/app-manage-policies-modal';
13	
14	type AppManagePoliciesModalWrapperProps = {
15	  pav: ProtectedApplicationViewKind;
16	};
17	
18	export const AppManagePoliciesModalWrapper: React.FC<
19	  CommonModalProps<AppManagePoliciesModalWrapperProps>
20	> = ({ isOpen, closeModal, extraProps: { pav } }) => {
21	  const { application, loaded, error } = useApplicationFromPAV(pav);
22	
23	  if (!loaded || error || !application) {
24	    return (
25	      <Modal
26	        variant={ModalVariant.small}
27	        isOpen={isOpen}
28	        onClose={closeModal}
29	        title="Manage disaster recovery"
30	      >
31	        {!loaded ? (
32	          <Bullseye>
33	            <Spinner size="lg" />
34	          </Bullseye>
35	        ) : (
36	          <Alert variant="danger" title="Failed to fetch application">
37	            {error?.message}
38	          </Alert>
39	        )}
40	      </Modal>
41	    );
42	  }
43	
44	  return (
45	    <AppManagePoliciesModal
46	      resource={application}
47	      isOpen={isOpen}
48	      close={closeModal}
49	    />
50	  );
51	};

